seleccionar_configuracion (materializado='tabla')  seleccion kunden.kunden_nr como  'Id' , COALESCE(kunden.firmenname, kunden.kunden_nr) como  'Nombre' , kunden.erp_nummer como  'ERP_Numero__c' , CASO CUANDO INFERIOR(kunden.kategorie) = 'oro' ENTONCES 'Oro' CUANDO INFERIOR(kunden.kategorie) = 'plata' ENTONCES 'Plata' CUANDO INFERIOR(kunden.kategorie) = 'bronce' ENTONCES 'Bronce' CUANDO INFERIOR(kunden.kategorie) = 'platino' ENTONCES 'Platino' SINO NULO FIN como  'Nivel_Cliente__c' , kunden.gebiet como  'Region__c' , kunden.branche como  'Industria' , kunden.webseite como  'Sitio_web' , kunden.ort como  'Ciudad_Facturacion' , kunden.land como  'Pais_Facturacion' , kunden.kunden_nr como  'Id_Cliente_Legado__c' , NULO::TEXTO como  'Fecha_Creacion' , NULO::TEXTO como  'Fecha_Ultima_Modificacion' , 0 como  'Es_Borrado'  DE  fuente('fixture_wrong_field_names_v2_src', 'kunden')  como kunden